code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Button, Chip, icon } from 'decantr/components';

code.example:
function ContentDetailHero({ item }) {
  const { div, h1, p, span, nav, a } = tags;

  return div({ class: css('_flex _col _gap4 _py8 _px6 _borderb _bordermuted/20') },
    nav({ class: css('_flex _aic _gap2 _textxs _fgmuted') },
      a({ href: '/registry', class: css('_hover:fgfg') }, 'Registry'),
      span({}, '/'),
      a({ href: `/registry/${item.type}`, class: css('_hover:fgfg') }, item.type),
      span({}, '/'),
      span({ class: css('_fgfg') }, item.name)
    ),
    div({ class: css('_flex _aic _gap2') },
      Chip({ size: 'sm' }, item.type),
      Badge({ variant: item.namespace === '@official' ? 'primary' : 'secondary', size: 'sm' }, item.namespace)
    ),
    h1({ class: css('_heading2') }, item.name),
    p({ class: css('_body _fgmuted _mw[720px]') }, item.description),
    div({ class: css('_flex _aic _gap4 _textxs _fgmuted') },
      span({}, `v${item.version}`),
      span({}, `Updated ${item.updated_at}`)
    ),
    div({ class: css('_flex _gap3') },
      Button({ variant: 'primary', size: 'sm' }, icon('copy', { size: '1em' }), ' Copy JSON'),
      Button({ variant: 'outline', size: 'sm' }, icon('download', { size: '1em' }), ' Use in Project'),
      Button({ variant: 'ghost', size: 'sm' }, icon('share', { size: '1em' }))
    )
  );
}

